import React from 'react';
import { Link } from 'react-router-dom';
import BookingForm from '../components/BookingForm'; // Reuse for quick enquiry, but simplify

const Home = () => {
  return (
    <div className="p-4">
      <h1>Welcome to Ranthambhore Safari Booking</h1>
      <p>Details about the safari, filler content...</p>
      <Link to="/booking" className="bg-blue-500 text-white p-2">Go to Booking</Link>
      <h2>Quick Enquiry</h2>
      <BookingForm /> {/* Simplified version without payment */}
    </div>
  );
};

export default Home;
